const response = $input.first().json;
const conversationId = response.conversation_id || response.id;
if (!conversationId) throw new Error('OpenHands did not return a conversation_id: ' + JSON.stringify(response));
return [{ json: {
  conversation_id: conversationId,
  project_id: $('Build OpenHands Prompt').first().json.project_id,
  github_repo_url: $('Build OpenHands Prompt').first().json.github_repo_url,
  github_repo_name: $('Build OpenHands Prompt').first().json.github_repo_name,
  poll_count: 0
} }];

const pollData = $('Save Conversation ID').first().json;
const newPollCount = (pollData.poll_count || 0) + 1;
if (newPollCount > 60) {
  throw new Error('OpenHands task timed out after 30 minutes. Conversation: ' + pollData.conversation_id);
}
return [{ json: { ...pollData, poll_count: newPollCount } }];

const ohResponse = $input.first().json;
const messages = ohResponse.messages || [];
const lastAgentMessage = [...messages].reverse().find(m => m.source === 'agent');
const lastMessageContent = lastAgentMessage?.content || '';
const isSuccess = lastMessageContent.includes('TASK COMPLETE') || lastMessageContent.includes('pushed to') || lastMessageContent.includes('pull request');

const convData = $('Save Conversation ID').first().json;

return [{ json: {
  conversation_id: convData.conversation_id,
  project_id: convData.project_id,
  github_repo_url: convData.github_repo_url,
  github_repo_name: convData.github_repo_name,
  task_succeeded: isSuccess,
  last_message: lastMessageContent.substring(0, 500),
  status: ohResponse.status
} }];
